     1→<!DOCTYPE html>
     2→<html lang="zh-CN">
     3→<head>
     4→    <meta charset="UTF-8">
     5→    <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→    <title>倒计时</title>
     7→    <style>
     8→        * {
     9→            margin: 0;
    10→            padding: 0;
    11→            box-sizing: border-box;
    12→        }
    13→        body {
    14→            min-height: 100vh;
    15→            display: flex;
    16→            flex-direction: column;
    17→            justify-content: center;
    18→            align-items: center;
    19→            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
    20→            font-family: 'Segoe UI', sans-serif;
    21→            color: #fff;
    22→        }
    23→        h1 {
    24→            font-size: 2rem;
    25→            margin-bottom: 2rem;
    26→            font-weight: 300;
    27→            letter-spacing: 0.5em;
    28→        }
    29→        .countdown {
    30→            display: flex;
    31→            gap: 1.5rem;
    32→        }
    33→        .time-unit {
    34→            display: flex;
    35→            flex-direction: column;
    36→            align-items: center;
    37→            background: rgba(255, 255, 255, 0.1);
    38→            padding: 1.5rem 2rem;
    39→            border-radius: 12px;
    40→            backdrop-filter: blur(10px);
    41→            min-width: 100px;
    42→        }
    43→        .number {
    44→            font-size: 3.5rem;
    45→            font-weight: 700;
    46→            color: #00d9ff;
    47→            text-shadow: 0 0 20px rgba(0, 217, 255, 0.5);
    48→        }
    49→        .label {
    50→            font-size: 0.875rem;
    51→            color: rgba(255, 255, 255, 0.7);
    52→            margin-top: 0.5rem;
    53→            text-transform: uppercase;
    54→            letter-spacing: 0.1em;
    55→        }
    56→        .input-section {
    57→            margin-top: 3rem;
    58→            display: flex;
    59→            gap: 1rem;
    60→            align-items: center;
    61→        }
    62→        input {
    63→            padding: 0.75rem 1rem;
    64→            border: none;
    65→            border-radius: 8px;
    66→            font-size: 1rem;
    67→            background: rgba(255, 255, 255, 0.15);
    68→            color: #fff;
    69→            outline: none;
    70→        }
    71→        input::placeholder {
    72→            color: rgba(255, 255, 255, 0.5);
    73→        }
    74→        button {
    75→            padding: 0.75rem 1.5rem;
    76→            border: none;
    77→            border-radius: 8px;
    78→            font-size: 1rem;
    79→            cursor: pointer;
    80→            background: #00d9ff;
    81→            color: #1a1a2e;
    82→            font-weight: 600;
    83→            transition: transform 0.2s, box-shadow 0.2s;
    84→        }
    85→        button:hover {
    86→            transform: translateY(-2px);
    87→            box-shadow: 0 5px 20px rgba(0, 217, 255, 0.4);
    88→        }
    89→        .target-date {
    90→            margin-top: 2rem;
    91→            color: rgba(255, 255, 255, 0.6);
    92→            font-size: 0.9rem;
    93→        }
    94→    </style>
    95→</head>
    96→<body>
    97→    <h1>倒计时</h1>
    98→
    99→    <div class="countdown">
   100→        <div class="time-unit">
   101→            <span class="number" id="days">00</span>
   102→            <span class="label">天</span>
   103→        </div>
   104→        <div class="time-unit">
   105→            <span class="number" id="hours">00</span>
   106→            <span class="label">时</span>
   107→        </div>
   108→        <div class="time-unit">
   109→            <span class="number" id="minutes">00</span>
   110→            <span class="label">分</span>
   111→        </div>
   112→        <div class="time-unit">
   113→            <span class="number" id="seconds">00</span>
   114→            <span class="label">秒</span>
   115→        </div>
   116→    </div>
   117→
   118→    <div class="input-section">
   119→        <input type="datetime-local" id="datetimeInput">
   120→        <button onclick="startCountdown()">开始倒计时</button>
   121→    </div>
   122→
   123→    <div class="target-date" id="targetDisplay"></div>
   124→
   125→    <script>
   126→        let targetTime = null;
   127→        let countdownInterval = null;
   128→
   129→        function updateCountdown() {
   130→            if (!targetTime) return;
   131→
   132→            const now = new Date().getTime();
   133→            const distance = targetTime - now;
   134→
   135→            if (distance <= 0) {
   136→                document.getElementById('days').textContent = '00';
   137→                document.getElementById('hours').textContent = '00';
   138→                document.getElementById('minutes').textContent = '00';
   139→                document.getElementById('seconds').textContent = '00';
   140→                clearInterval(countdownInterval);
   141→                return;
   142→            }
   143→
   144→            const days = Math.floor(distance / (1000 * 60 * 60 * 24));
   145→            const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
   146→            const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
   147→            const seconds = Math.floor((distance % (1000 * 60)) / 1000);
   148→
   149→            document.getElementById('days').textContent = String(days).padStart(2, '0');
   150→            document.getElementById('hours').textContent = String(hours).padStart(2, '0');
   151→            document.getElementById('minutes').textContent = String(minutes).padStart(2, '0');
   152→            document.getElementById('seconds').textContent = String(seconds).padStart(2, '0');
   153→        }
   154→
   155→        function startCountdown() {
   156→            const input = document.getElementById('datetimeInput').value;
   157→            if (!input) {
   158→                alert('请选择目标时间');
   159→                return;
   160→            }
   161→
   162→            targetTime = new Date(input).getTime();
   163→
   164→            document.getElementById('targetDisplay').textContent = '目标时间: ' + input.replace('T', ' ');
   165→
   166→            if (countdownInterval) {
   167→                clearInterval(countdownInterval);
   168→            }
   169→
   170→            updateCountdown();
   171→            countdownInterval = setInterval(updateCountdown, 1000);
   172→        }
   173→    </script>
   174→</body>
   175→</html>
